(51,1,'ehrlumf','Umfrage Ehrlichkeit','<table border=\"1\" style=\"border-collapse: collapse; width: 100%;\"><thead><tr><th>Thema</th><th>Frage</th><th>Ja</th><th>Nein</th></tr></thead><tbody><tr><td rowspan=\"5\">Ehrlichkeit</td><td>Sagst du die Wahrheit, auch wenn sie unangenehm ist?</td><td><input type=\"radio\" name=\"ehrlichkeit1\" value=\"ja\"></td><td><input type=\"radio\" name=\"ehrlichkeit1\" value=\"nein\"></td></tr><tr><td>Findest du, dass Verschweigen auch unehrlich sein kann?</td><td><input type=\"radio\" name=\"ehrlichkeit2\" value=\"ja\"></td><td><input type=\"radio\" name=\"ehrlichkeit2\" value=\"nein\"></td></tr><tr><td>Würdest du einen Fehler sofort zugeben?</td><td><input type=\"radio\" name=\"ehrlichkeit3\" value=\"ja\"></td><td><input type=\"radio\" name=\"ehrlichkeit3\" value=\"nein\"></td></tr><tr><td>Ist es dir wichtig, dass dein Partner alles offen anspricht?</td><td><input type=\"radio\" name=\"ehrlichkeit4\" value=\"ja\"></td><td><input type=\"radio\" name=\"ehrlichkeit4\" value=\"nein\"></td></tr><tr><td>Ist für dich eine Notlüge in der Beziehung akzeptabel?</td><td><input type=\"radio\" name=\"ehrlichkeit5\" value=\"ja\"></td><td><input type=\"radio\" name=\"ehrlichkeit5\" value=\"nein\"></td></tr><tr><td rowspan=\"5\">Treue</td><td>Bedeutet Treue für dich auch Treue in Gedanken, nicht nur im Verhalten?</td><td><input type=\"radio\" name=\"treue1\" value=\"ja\"></td><td><input type=\"radio\" name=\"treue1\" value=\"nein\"></td></tr><tr><td>Wäre heimliches Flirten für dich bereits Untreue?</td><td><input type=\"radio\" name=\"treue2\" value=\"ja\"></td><td><input type=\"radio\" name=\"treue2\" value=\"nein\"></td></tr><tr><td>Ist emotionales Fremdgehen für dich gleich schlimm wie körperliches?</td><td><input type=\"radio\" name=\"treue3\" value=\"ja\"></td><td><input type=\"radio\" name=\"treue3\" value=\"nein\"></td></tr><tr><td>Würdest du klar sagen, wenn Gefühle für jemand anderen entstehen?</td><td><input type=\"radio\" name=\"treue4\" value=\"ja\"></td><td><input type=\"radio\" name=\"treue4\" value=\"nein\"></td></tr><tr><td>Ist Treue für dich eine unverhandelbare Grundlage?</td><td><input type=\"radio\" name=\"treue5\" value=\"ja\"></td><td><input type=\"radio\" name=\"treue5\" value=\"nein\"></td></tr><tr><td rowspan=\"5\">Vertrauen</td><td>Vertraust du deinem Partner ohne ständige Kontrolle?</td><td><input type=\"radio\" name=\"vertrauen1\" value=\"ja\"></td><td><input type=\"radio\" name=\"vertrauen1\" value=\"nein\"></td></tr><tr><td>Darf dein Partner private Chats ohne Erklärungsdruck haben?</td><td><input type=\"radio\" name=\"vertrauen2\" value=\"ja\"></td><td><input type=\"radio\" name=\"vertrauen2\" value=\"nein\"></td></tr><tr><td>Kann Vertrauen nach einem Bruch wieder vollständig zurückkommen?</td><td><input type=\"radio\" name=\"vertrauen3\" value=\"ja\"></td><td><input type=\"radio\" name=\"vertrauen3\" value=\"nein\"></td></tr><tr><td>Ist Eifersucht für dich eher ein Zeichen von Unsicherheit als von Liebe?</td><td><input type=\"radio\" name=\"vertrauen4\" value=\"ja\"></td><td><input type=\"radio\" name=\"vertrauen4\" value=\"nein\"></td></tr><tr><td>Würdest du offen sagen, wenn etwas dein Vertrauen schwächt?</td><td><input type=\"radio\" name=\"vertrauen5\" value=\"ja\"></td><td><input type=\"radio\" name=\"vertrauen5\" value=\"nein\"></td></tr><tr><td rowspan=\"5\">Respekt</td><td>Kann man jemanden lieben, aber im Streit respektlos werden?</td><td><input type=\"radio\" name=\"respekt1\" value=\"ja\"></td><td><input type=\"radio\" name=\"respekt1\" value=\"nein\"></td></tr><tr><td>Ist es für dich respektlos, den Partner vor anderen schlechtzumachen?</td><td><input type=\"radio\" name=\"respekt2\" value=\"ja\"></td><td><input type=\"radio\" name=\"respekt2\" value=\"nein\"></td></tr><tr><td>Akzeptierst du andere Meinungen deines Partners auch bei klarer Uneinigkeit?</td><td><input type=\"radio\" name=\"respekt3\" value=\"ja\"></td><td><input type=\"radio\" name=\"respekt3\" value=\"nein\"></td></tr><tr><td>Gehören Grenzen (z. B. Privatsphäre) für dich zum Respekt?</td><td><input type=\"radio\" name=\"respekt4\" value=\"ja\"></td><td><input type=\"radio\" name=\"respekt4\" value=\"nein\"></td></tr><tr><td>Ist Zuhören für dich ein Zeichen von Respekt?</td><td><input type=\"radio\" name=\"respekt5\" value=\"ja\"></td><td><input type=\"radio\" name=\"respekt5\" value=\"nein\"></td></tr><tr><td rowspan=\"5\">Kommunikation</td><td>Sollte man Konflikte möglichst sofort klären?</td><td><input type=\"radio\" name=\"kommunikation1\" value=\"ja\"></td><td><input type=\"radio\" name=\"kommunikation1\" value=\"nein\"></td></tr><tr><td>Ist Schweigen im Streit für dich manchmal sinnvoll?</td><td><input type=\"radio\" name=\"kommunikation2\" value=\"ja\"></td><td><input type=\"radio\" name=\"kommunikation2\" value=\"nein\"></td></tr><tr><td>Sollten wichtige Themen immer persönlich statt per Chat besprochen werden?</td><td><input type=\"radio\" name=\"kommunikation3\" value=\"ja\"></td><td><input type=\"radio\" name=\"kommunikation3\" value=\"nein\"></td></tr><tr><td>Darf man in einer Beziehung auch sagen: „Ich brauche jetzt Zeit für mich“?</td><td><input type=\"radio\" name=\"kommunikation4\" value=\"ja\"></td><td><input type=\"radio\" name=\"kommunikation4\" value=\"nein\"></td></tr><tr><td>Ist gute Kommunikation lernbar, auch wenn es anfangs schwierig ist?</td><td><input type=\"radio\" name=\"kommunikation5\" value=\"ja\"></td><td><input type=\"radio\" name=\"kommunikation5\" value=\"nein\"></td></tr></tbody></table>',0,'2026-02-20 13:55:04','2026-02-20 13:55:04',NULL),
(52,1,'ehrlumf','Umfrage Ehrlichkeit','<umfrage-matrix titel=\"Ehrlichkeit, Treue, Vertrauen, Respekt, Kommunikation\">\n  <frage kategorie=\"Ehrlichkeit\" name=\"ehrlichkeit1\">Sagst du die Wahrheit, auch wenn sie unangenehm ist?</frage>\n  <frage kategorie=\"Ehrlichkeit\" name=\"ehrlichkeit2\">Findest du, dass Verschweigen auch unehrlich sein kann?</frage>\n  <frage kategorie=\"Ehrlichkeit\" name=\"ehrlichkeit3\">Würdest du einen Fehler sofort zugeben?</frage>\n  <frage kategorie=\"Ehrlichkeit\" name=\"ehrlichkeit4\">Ist es dir wichtig, dass dein Partner alles offen anspricht?</frage>\n  <frage kategorie=\"Ehrlichkeit\" name=\"ehrlichkeit5\">Ist für dich eine Notlüge in der Beziehung akzeptabel?</frage>\n  <frage kategorie=\"Treue\" name=\"treue1\">Bedeutet Treue für dich auch Treue in Gedanken, nicht nur im Verhalten?</frage>\n  <frage kategorie=\"Treue\" name=\"treue2\">Wäre heimliches Flirten für dich bereits Untreue?</frage>\n  <frage kategorie=\"Treue\" name=\"treue3\">Ist emotionales Fremdgehen für dich gleich schlimm wie körperliches?</frage>\n  <frage kategorie=\"Treue\" name=\"treue4\">Würdest du klar sagen, wenn Gefühle für jemand anderen entstehen?</frage>\n  <frage kategorie=\"Treue\" name=\"treue5\">Ist Treue für dich eine unverhandelbare Grundlage?</frage>\n  <frage kategorie=\"Vertrauen\" name=\"vertrauen1\">Vertraust du deinem Partner ohne ständige Kontrolle?</frage>\n  <frage kategorie=\"Vertrauen\" name=\"vertrauen2\">Darf dein Partner private Chats ohne Erklärungsdruck haben?</frage>\n  <frage kategorie=\"Vertrauen\" name=\"vertrauen3\">Kann Vertrauen nach einem Bruch wieder vollständig zurückkommen?</frage>\n  <frage kategorie=\"Vertrauen\" name=\"vertrauen4\">Ist Eifersucht für dich eher ein Zeichen von Unsicherheit als von Liebe?</frage>\n  <frage kategorie=\"Vertrauen\" name=\"vertrauen5\">Würdest du offen sagen, wenn etwas dein Vertrauen schwächt?</frage>\n  <frage kategorie=\"Respekt\" name=\"respekt1\">Kann man jemanden lieben, aber im Streit respektlos werden?</frage>\n  <frage kategorie=\"Respekt\" name=\"respekt2\">Ist es für dich respektlos, den Partner vor anderen schlechtzumachen?</frage>\n  <frage kategorie=\"Respekt\" name=\"respekt3\">Akzeptierst du andere Meinungen deines Partners auch bei klarer Uneinigkeit?</frage>\n  <frage kategorie=\"Respekt\" name=\"respekt4\">Gehören Grenzen (z. B. Privatsphäre) für dich zum Respekt?</frage>\n  <frage kategorie=\"Respekt\" name=\"respekt5\">Ist Zuhören für dich ein Zeichen von Respekt?</frage>\n  <frage kategorie=\"Kommunikation\" name=\"kommunikation1\">Sollte man Konflikte möglichst sofort klären?</frage>\n  <frage kategorie=\"Kommunikation\" name=\"kommunikation2\">Ist Schweigen im Streit für dich manchmal sinnvoll?</frage>\n  <frage kategorie=\"Kommunikation\" name=\"kommunikation3\">Sollten wichtige Themen immer persönlich statt per Chat besprochen werden?</frage>\n  <frage kategorie=\"Kommunikation\" name=\"kommunikation4\">Darf man in einer Beziehung auch sagen: „Ich brauche jetzt Zeit für mich“?</frage>\n  <frage kategorie=\"Kommunikation\" name=\"kommunikation5\">Ist gute Kommunikation lernbar, auch wenn es anfangs schwierig ist?</frage>\n</umfrage-matrix>',0,'2026-02-20 14:00:06','2026-02-20 14:00:06',NULL),
